<template>
  <v-container fluid class="pa-6 pt-4 fill-height cctv-monitoring-manage white" ref="cctvReference">
    <v-row no-gutters class="fill-height">
      <v-sheet width="100%" height="33" class="d-flex align-center">
        <h3 class="font-weight-bold">{{ title }}</h3>
        <v-spacer />
        <v-tooltip left>
          <template #activator="{ on, attrs }">
            <v-btn
              icon
              :ripple="false"
              v-bind="attrs"
              v-on="on"
              @click.prevent="isFullScreen ? closeFullScreen() : onFullScreen()"
            >
              <v-icon>{{ `${isFullScreen ? 'mdi-fullscreen-exit' : 'mdi-fullscreen'}` }}</v-icon>
            </v-btn>
          </template>
          <span>{{ `전체화면 ${isFullScreen ? '닫기' : ''}` }}</span>
        </v-tooltip>
      </v-sheet>
      <v-sheet width="100%" height="calc(100% - 32px)" class="pt-2 overflow-hidden">
        <v-row no-gutters class="pa-0 fill-height">
          <v-card width="150" color="login_bg" class="pa-2 fill-height red d-flex flex-column">
            <v-list nav dense class="login_bg overflow-y-auto">
              <v-list-item-group v-model="selected" color="primary" class="login_bg">
                <template v-for="(item, i) in groupList">
                  <v-list-item :key="i" :input-value="item.Profile_id" :value="item.Profile_id" class="login_bg pr-0" :class="{ 'selected-list-item' : item.Profile_id == selected }">
                    <v-list-item-content @click="handleCCTV(item.Profile_id)">
                      <v-list-item-title class="text-subtitle-2">
                        {{ item.Profile_name }}
                      </v-list-item-title>
                    </v-list-item-content>
                    <v-list-item-action>
                      <v-btn icon :ripple="false" @click.stop="deleteGroup($event, item)">
                        <svg-icon width="18" height="18" icon-class="delete_condition" color="grey" />
                      </v-btn>
                    </v-list-item-action>
                  </v-list-item>
                </template>
              </v-list-item-group>
            </v-list>
            <v-btn
              height="36"
              color="btn_bg"
              class="mt-1 white px-0 pr-2"
              elevation="0"
              outlined
              rounded
              small
              width="100%"
              @click="saveGroupBtn"
            >
              <div class="font-weight-bold content--text">
                <v-icon size="14" class="mr-1">{{ `mdi-plus` }}</v-icon>
                {{ `그룹추가` }}
              </div>
            </v-btn>
          </v-card>
          <v-col class="fill-height overflow-x-hidden overflow-y-auto">
            <v-sheet width="100%" height="32" class="pl-4 pr-2 d-flex align-center">
              <span class="mr-2">그룹 명</span>
              <v-sheet width="200" height="100%">
                <v-text-field
                  v-model="selectedGroup.Profile_name"
                  outlined
                  clearable
                />
              </v-sheet>
              <v-spacer />
              <v-btn
                height="32"
                color="btn_bg"
                class="mt-1 mr-3 px-0"
                elevation="0"
                outlined
                rounded
                small
                width="65"
                @click="handleCCTVPop('setting')"
              >
                <div class="font-weight-bold content--text">
                  {{ `설정` }}
                </div>
              </v-btn>
              <v-btn
                height="32"
                color="btn_bg"
                class="mt-1 px-0"
                elevation="0"
                outlined
                rounded
                small
                width="65"
                @click="saveLayout"
              >
                <div class="font-weight-bold content--text">
                  {{ `저장` }}
                </div>
              </v-btn>
            </v-sheet>
            <v-sheet width="100%" height="calc(100% - 32px)" class="overflow-x-hidden overflow-y-auto">
              <smart-widget-grid
                :layout="layout"
                :colNum="48"
                :rowHeight="48"
                :headerHeight="40"
                fixedHeight
                shadow="never"
                class="fill-height"
              >
                <template v-for="(cctv, cctv_index) in layout">
                  <smart-widget :key="cctv.i" :slot="cctv.i">
                    <template #title>
                      <v-icon class="mr-2">mdi-cctv</v-icon>
                      <v-text-field
                        v-model="cctv.title"
                        outlined
                        clearable
                      />
                    </template>
                    <template #toolbar>
                      <v-sheet height="100%" class="pr-2">
                        <v-tooltip top>
                          <template #activator="{ on, attrs }">
                            <v-btn v-on="on" v-bind="attrs" icon :ripple="false" class="" @click.prevent="onVideoFullScreen(cctv_index)">
                              <v-icon>mdi-fullscreen</v-icon>
                            </v-btn>
                          </template>
                          <span>{{ `전체화면` }}</span>
                        </v-tooltip>
                        <v-tooltip top>
                          <template #activator="{ on, attrs }">
                            <v-btn v-on="on" v-bind="attrs" icon :ripple="false" class="" @click.prevent="deleteWidget(cctv.i)">
                              <v-icon>mdi-close</v-icon>
                            </v-btn>
                          </template>
                          <span>{{ `카메라 삭제` }}</span>
                        </v-tooltip>
                      </v-sheet>
                    </template>
                    <template #default>
                      <v-sheet width="100%" height="100%" color="#1E1E1E" class="d-flex align-center justify-center" :ref="`videoIframe${cctv_index}`">
                        <template v-if="loading[cctv_index]">
                          <v-progress-circular indeterminate color="white" />
                        </template>
                        <template v-if="cctv.cctv_play_url">
                          <iframe
                            v-show="!loading[cctv_index]"
                            width="100%"
                            height="100%"
                            :src="`${cctv.cctv_play_url}?controls=0`"
                            frameborder="0"
                            :allowfullscreen="true"
                            allow="fullscreen; encrypted-media; autoplay;"
                            :class="['iframe-class', cctv.class]"
                            @load="onVideoLoad(cctv_index)"
                          />
                        </template>
                        <template v-else>
                          추가된 위젯
                        </template>
                        <template v-if="isVideoFullScreen">
                          <h1 class="ma-3 full-screen-title font-weight-bold warning--text">{{ `${cctv.cctv_id}` }}</h1>
                          <v-btn icon :ripple="false" class="ma-3 full-screen-close-button" @click.prevent="closeFullScreen">
                            <v-icon size="42" color="white">mdi-close</v-icon>
                          </v-btn>
                        </template>
                      </v-sheet>
                    </template>
                  </smart-widget>
                </template>
              </smart-widget-grid>
              <template v-if="layout.length == 0">
                <span class="cctv-monitoring-manage-empty-text">연결된 카메라가 없습니다.</span>
              </template>
            </v-sheet>
          </v-col>
        </v-row>
      </v-sheet>
    </v-row>
    <v-dialog v-model="isCCTVList" persistent width="500">
      <v-card class="pa-4">
        <v-card-title class="pa-0 pb-4 text-subtitle-1 font-weight-bold primary--text">
          {{ `카메라 리스트` }}
        </v-card-title>
        <v-card-text class="pa-0">
          <v-list height="450" nav dense class="login_bg overflow-y-auto">
            <v-list-item-group v-model="selectedCCTV" multiple color="primary" class="pa-2 login_bg">
              <template v-for="(cctv, i) in cctvList">
                <v-list-item
                  :key="i"
                  :input-value="cctv.cctv_id"
                  :value="cctv.cctv_id"
                  :disabled="legacyCCTVKeyList.includes(cctv.i)"
                  class="login_bg pr-0"
                  >
                  <v-list-item-content>
                    <v-list-item-title class="text-subtitle-2">
                      {{ `${cctv.camera_desc} (${cctv.cctv_name})` }}
                    </v-list-item-title>
                  </v-list-item-content>
                  <v-list-item-action>
                  </v-list-item-action>
                </v-list-item>
              </template>
            </v-list-item-group>
          </v-list>
        </v-card-text>
        <v-card-actions class="pa-0 pt-4">
          <v-spacer />
          <v-btn small text outlined height="35" width="70" class="mr-1" color="primary" @click="handleCCTVPop('save')">
            {{ $t('apply') }}
          </v-btn>
          <v-btn small text outlined height="35" width="70" color="error" @click="handleCCTVPop('cancel')">
            {{ $t('btnCancel') }}
          </v-btn>
        </v-card-actions>
      </v-card>
    </v-dialog>
  </v-container>
</template>

<script>
import { getUserCd } from '@/utils/token'
import { getCCTVList } from '@/api/realTimeVideoSafetyManagement/safetyDetectionCameraManage.js'
import { getGroupList, saveGroup, deleteGroup,
   getMonitoringList, setMonitoringList, deleteMonitoringList, setVideoStart, getVideo } from '@/api/realTimeVideoSafetyManagement/safetyMonitoring.js'
import { getAiServerList, startAiProcess, refreshAiProcess } from '@/api/realTimeVideoSafetyManagement/safetyVideoServerManage.js'

import baseview from '@/views/base/baseview.vue' //20220414 LYJ base page 추가
export default {
  mixins: [baseview],
  name: 'SafetyMonitoringManage',
  components: {
  },
  computed: {
    legacyCCTVKeyList() {
      return this.layout.map(el => el.i).filter(el => !this.deleteLayoutIndexs.includes(el))
    }
  },
  data() {
    return {
      title: '모니터링 설정',
      selected: 0,
      selectedGroup: {},
      legacyGroupList: [],
      groupList: [],
      legacyCCTVKeys: [],
      layout: [],
      deleteLayoutIndexs: [],
      loading: [],
      loadingDelay: 1000,
      isFullScreen: false,
      isVideoFullScreen: false,
      isCCTVList: false,
      selectedCCTV: [],
      cctvList: []
    }
  },
  methods: {
    handleKeydown(event) {
      if (this.isVideoFullScreen && event.key === 'Escape') {
        this.closeFullScreen()
      }
    },
    handleRatioClass(ratio) {
      let [x, y] = ratio ? ratio.split(':').map(Number) : [4, 3]
      return `ratio-${x}-${y}`
    },
    handleCreated(isNew) {
      getGroupList()
        .then(res => {
          this.groupList = res.list
          this.legacyGroupList = res.list
          if(this.groupList.length !== 0) {
            if(isNew) {
              this.selected = this.groupList[0].Profile_id
              this.selectedGroup = JSON.parse(JSON.stringify(this.groupList[0]))
            }
            this.handleCCTV(this.selected)
          }
        })
        .catch(() => {
          console.error('서버의 상태가 원활하지않습니다.')
          return
        })
        .finally(() => {
          getCCTVList()
            .then(res => {
              this.cctvList = res.list
            })
        })
    },
    handleCCTV(param) {
      this.layout = []
      this.selectedGroup = JSON.parse(JSON.stringify(this.groupList.find(el => el.Profile_id == param)))
      if(!this.selectedGroup?.__created__) {
        this.openLoading()
        getMonitoringList(param)
          .then(res => {
            this.loading = Array(res.list.length).fill(true)
            this.layout = res.list.map((el, index) => {
              return {
                ...el,
                class: this.handleRatioClass(el.ratio)
              }
            })
            this.legacyCCTVKeys = res.list.map(el => el.i)
          })
          .finally(() => {
            this.endLoading()
          })
      }
    },
    onVideoLoad(index) {
      setTimeout(() => {
        this.$set(this.loading, index, false)
      }, this.loadingDelay)
    },
    async onFullScreen(container) {
      if(!container) {
        container = this.$refs.cctvReference
        this.isFullScreen = true
      }
      if (container.requestFullscreen) {
        container.requestFullscreen()
      } else if (container.mozRequestFullScreen) {
        container.mozRequestFullScreen()
      } else if (container.webkitRequestFullscreen) {
        container.webkitRequestFullscreen()
      } else if (container.msRequestFullscreen) {
        container.msRequestFullscreen()
      }
    },
    async onVideoFullScreen(index) {
      const container = this.$refs['videoIframe' + index][0]?.$el
      this.onFullScreen(container)
      this.$nextTick(() => {
        window.addEventListener('keydown', this.handleKeydown)
      })
      this.isVideoFullScreen = true
    },
    closeFullScreen() {
      if (document.exitFullscreen) {
        document.exitFullscreen()
      } else if (document.mozCancelFullScreen) {
        document.mozCancelFullScreen()
      } else if (document.webkitExitFullscreen) {
        document.webkitExitFullscreen()
      } else if (document.msExitFullscreen) {
        document.msExitFullscreen()
      }
      this.isVideoFullScreen = false
      this.isFullScreen = false
    },
    // ----------------------------------
    saveGroupBtn(isNew) {
      this.openLoading('saving')
      const param = {
        Profile_name: isNew ? `새그룹 ${this.groupList.length}` : this.selectedGroup?.Profile_name,
        userCd: getUserCd(),
      }
      if(isNew) {
        Object.assign(param, { __created__: true })
      } else {
        Object.assign(param, { Profile_id: this.selectedGroup?.Profile_id })
      }
      saveGroup([param], isNew)
        .then(res => {
          if(res.add_count !== 0 || res.update_count !== 0) {
            this.handleCreated(false)
          }
        })
        .finally(() => {
          this.endLoading()
        })
    },
    deleteGroup(e, param) {
      e.preventDefault()
      this.vToastifyPrompt(
        `저장된 카메라 정보가 삭제됩니다. 삭제하시겠습니까?`,
        'warn',
        current => {
          const deleteParam = param.Profile_id
          if(deleteParam) {
            this.openLoading()
            deleteGroup([deleteParam])
              .then(res => {
                this.handleCreated(true)
              })
              .finally(() => {
                this.endLoading()
              })
          }
        },
        null,
        true
      )
    },
    deleteWidget(e) {
      this.layout = this.layout.filter(el => el.i !== e)
      if(this.legacyCCTVKeys.includes(e) && !this.deleteLayoutIndexs.includes(e)) {
        this.deleteLayoutIndexs.push(e)
      }
    },
    saveLayout() {
      this.vToastifyPrompt(
        this.$t('doSaveData'),
        'info',
        current => {
          const param = this.layout.map(el => {
            const { profile_id, cctv_id, w, h, x, y, i, title, __created__ } = el
            let newObject = { profile_id, cctv_id, w, h, x, y, i, title,
              userCd: getUserCd()
            }
            if(__created__) {
              Object.assign(newObject, { __created__ })
            }
            return newObject
          })
          if(this.deleteLayoutIndexs.length !== 0) {
            const isEmptyLayout = param.length == 0
            const deleteParam = this.deleteLayoutIndexs.map(el => `${this.selectedGroup.Profile_id}_${el}`)
            deleteMonitoringList(deleteParam, isEmptyLayout)
              .then(res => {
              })
          }
          if(param.length !== 0) {
            setMonitoringList(param, true)
              .then(res => {
                
              })
          }
          if(this.selectedGroup.Profile_name !== this.groupList.find(el => el.Profile_id == this.selectedGroup.Profile_id)?.Profile_name) {
            this.saveGroupBtn(false)
          }
            
        },
        null,
        true
      )
    },
    handleCCTVPop(key) {
      switch (key) {
        case 'setting':
          this.isCCTVList = true
          break;
        case 'save':
          this.selectedCCTV.forEach((el, index) => {
            const profile_id = this.selectedGroup.Profile_id
            this.layout.push({
              profile_id,
              title: '',
              cctv_id: el,
              x: 0,
              y: 0,
              w: 15,
              h: 6,
              i: `New_${this.layout.length + 1}`,
              __created__: true
            })
          })
          setTimeout(() => {
            this.handleCCTVPop()
          }, 0);
          break;
        default:
          this.selectedCCTV = []
          this.isCCTVList = false
          break;
      }
    }
  },
  created() {
    this.handleCreated(true)
  },
  mounted() {
    document.addEventListener('fullscreenchange', () => {
      if (!document.fullscreenElement) {
        this.isVideoFullScreen = false
        this.isFullScreen = false
      }
    })
  },
  destroy() {
  },
  beforeRouteLeave(to, from, next) {
    window.removeEventListener('keydown', this.handleKeydown)
    next()
  }
}
</script>

<style lang="scss">
.cctv-monitoring-manage {
  $secondary: #3F51B5;
  $secondary-opacity: #3f51b544;
  height: calc(100vh - 126px);
  > div {
    position: relative;
    .v-list {
      height: calc(100% - 40px) !important;
      &-item {
        &__title {
          text-overflow: ellipsis;
          text-wrap: nowrap;
        }
        .svg-icon:hover {
          color: rgba(255, 0, 0, 0.7);
        }
        &.selected-list-item {
          .v-list-item__content {
            pointer-events: none;
          }
        }
      }
    }
    .v-list-item--dense, .v-list--dense .v-list-item {
      min-height: 36px !important;
      padding: 0 0 0 8px !important;
      margin-bottom: 8px !important;
    }
    .alert-card {
      &-right {
        margin-right: 6px;
      }
      &-left {
        margin-left: 6px;
      }
    }
    .vue-grid-layout {
      height: 100% !important;
      .widget {
        &-header {
          display: flex;
          align-items: center;
          padding-left: 16px;
        }
        &-body {
          &__content {
            padding: 0 !important;
            .iframe-class {
              pointer-events: none;
              width: auto;
              height: 100%;
              border: none;
              object-fit: cover;
            }
            .ratio-16-9 {
              aspect-ratio: 16 / 9;
            }
            .ratio-4-3 {
              aspect-ratio: 4 / 3;
            }
            .ratio-3-2 {
              aspect-ratio: 3 / 2;
            }
          }
        }
      }
    }
  }
  &-empty-text {
    position: absolute;
    top: 50%;
    left: 50%;
    transform: translate(-50%, -50%);
  }
  .full-screen {
    &-title {
      position: absolute;
      top: 0;
      left: 0;
    }
    &-close-button {
      position: absolute;
      top: 0;
      right: 0;
    }
  }
  .v-input {
    &__append-inner {
      margin: 0;
      display: flex;
      align-self: center;
    }
  }
}
</style>

